package br.com.estacionamento.ocupacao.config;import org.springframework.amqp.core.*;import org.springframework.context.annotation.*;@Configuration public class RabbitConfig{public static final String EXCHANGE="parking.events";@Bean DirectExchange exchange(){return new DirectExchange(EXCHANGE);}@Bean Queue ocupacaoQueue(){return QueueBuilder.durable("ocupacao.metricas").deadLetterExchange(EXCHANGE).deadLetterRoutingKey("ocupacao.dlq").build();}@Bean Queue ocupacaoDlq(){return QueueBuilder.durable("ocupacao.dlq").build();}@Bean Binding b1(){return BindingBuilder.bind(ocupacaoQueue()).to(exchange()).with("sensor.vaga");}@Bean Binding b2(){return BindingBuilder.bind(ocupacaoDlq()).to(exchange()).with("ocupacao.dlq");}}
